import{_ as a,o as t,c as n,ac as i}from"./chunks/framework.DnBnwVZk.js";const g=JSON.parse('{"title":"鱼和熊掌兼得：ACP协议搭建Vibe Coding环境","description":"","frontmatter":{"date":"2026-02-07T18:22:08.000Z","categories":["Vibe Coding"],"tags":["Vibe Coding","acp"],"publish":true},"headers":[],"relativePath":"views/skill/ai/acp/acp.md","filePath":"views/skill/ai/acp/acp.md","lastUpdated":1775803235000}'),r={name:"views/skill/ai/acp/acp.md"};function o(l,e,p,c,d,s){return t(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1770488528000"},[...e[0]||(e[0]=[i('<h1 id="鱼和熊掌兼得-acp协议搭建vibe-coding环境" tabindex="-1">鱼和熊掌兼得：ACP协议搭建Vibe Coding环境 <a class="header-anchor" href="#鱼和熊掌兼得-acp协议搭建vibe-coding环境" aria-label="Permalink to &quot;鱼和熊掌兼得：ACP协议搭建Vibe Coding环境&quot;">​</a></h1><p>一直以来，在我心目中，Vibe Coding工具环境的完美形态是IDE环境和最新的agent功能的完美结合，这个形态需要包含3个方面</p><ol><li>保持最新的agent能力，如Open Code类似，支持mcp，支持skill，支持自定义插件，支持自由切换模型</li><li>适配各种IDE，比如写Java项目的时候，我希望只打开IDEA就可以完成，而不需要为了ai功能，在<strong>一个项目打开多个代码环境</strong>，比如打开antigravity来修改代码，同时打开IDEA来使用类型和跳转、搜索等能力</li><li>ai chat框与代码编辑器的深度整合，典型的如代码片段的选择能力，通义灵码插件可以随时框选多段代码片段来放入提示词上下文，而不是在聊天框手搓：“给我修改a.b.c类的m方法”，稍显原始</li></ol><p>目前来看，通义灵码插件同时适配VSCode系以及Jetbrains系的IDE,是最接近上述形态的解决方案，唯一的不完美是感觉在agent能力层面稍逊一筹，略微差于Open Code类似的cli方案。</p><p>最新读到了<a href="https://zhuanlan.zhihu.com/p/2003423070828912693" target="_blank" rel="noreferrer">韩骏老师的文</a>，感觉ACP协议有望解决这个问题。</p><blockquote><p>ACP 解决的是：任何 AI Agent → 任何支持的编辑器</p></blockquote><p>acp协议官网列出了支持的<a href="https://agentclientprotocol.com/get-started/agents" target="_blank" rel="noreferrer">agent列表</a>和<a href="https://agentclientprotocol.com/get-started/clients" target="_blank" rel="noreferrer">IDE</a>，对我来说，目前常用的agent是Open Code，IDE是JetBrains系列以及VsCode(目前暂不支持)</p><h2 id="idea插件配置" tabindex="-1">IDEA插件配置 <a class="header-anchor" href="#idea插件配置" aria-label="Permalink to &quot;IDEA插件配置&quot;">​</a></h2><h3 id="下载插件" tabindex="-1">下载插件 <a class="header-anchor" href="#下载插件" aria-label="Permalink to &quot;下载插件&quot;">​</a></h3><p>打开idea的market place，下载<code>JetBrains AI Assistant</code>插件.</p><p><img src="https://cdn.jsdelivr.net/gh/kkyeer/picbed/download_plugin.png" alt="download_plugin"></p><h3 id="配置插件" tabindex="-1">配置插件 <a class="header-anchor" href="#配置插件" aria-label="Permalink to &quot;配置插件&quot;">​</a></h3><h4 id="安装opencode-agent插件" tabindex="-1">安装opencode agent插件 <a class="header-anchor" href="#安装opencode-agent插件" aria-label="Permalink to &quot;安装opencode agent插件&quot;">​</a></h4><p>在AI 聊天窗口的底部，点击**Install From ACP Registry``` <img src="https://cdn.jsdelivr.net/gh/kkyeer/picbed/install-from-acp.png" alt="install-from-acp"></p><p>在打开的窗口中安装对应的agent配置 <img src="https://cdn.jsdelivr.net/gh/kkyeer/picbed/select-agent.png" alt="select-agent"></p><h4 id="配置acp-json" tabindex="-1">配置acp.json <a class="header-anchor" href="#配置acp-json" aria-label="Permalink to &quot;配置acp.json&quot;">​</a></h4><p>在ai chat窗口点击右上角的三个点，在打开的option对话框点击<code>Add Custom Agent</code>按钮。</p><p><img src="https://cdn.jsdelivr.net/gh/kkyeer/picbed/chat-option.png" alt="chat-option"><img src="https://cdn.jsdelivr.net/gh/kkyeer/picbed/config-agent1.png" alt="config-agent1"></p><p>会打开acp.json配置文件的编辑窗口，插件自动探测到open code的安装位置，直接点击插入即可</p><p><img src="https://cdn.jsdelivr.net/gh/kkyeer/picbed/add-config.png" alt="add-config"></p><h4 id="使用效果" tabindex="-1">使用效果 <a class="header-anchor" href="#使用效果" aria-label="Permalink to &quot;使用效果&quot;">​</a></h4><p>上述配置完成后，在AI 聊天窗口即可选择Open Code，并且支持切换模型，以及在上下文嵌入代码文件引用</p><p><img src="https://cdn.jsdelivr.net/gh/kkyeer/picbed/ok.png" alt="ok"></p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://www.jetbrains.com/zh-cn/help/ai-assistant/acp.html#acp-troubleshooting" target="_blank" rel="noreferrer">Jetbrains官方文档</a></li><li><a href="https://zhuanlan.zhihu.com/p/2003423070828912693" target="_blank" rel="noreferrer">JetBrains IDE 重磅新功能：AI Agent 终于可以像插件一样使用了</a></li></ul>',25)])])}const b=a(r,[["render",o]]);export{g as __pageData,b as default};
